ylabel(ax, "Probability"); %[output:1d3ce009]
%[text] Set ranges on the axes.
%ylim(ax, [0, 0.2]);
xlim(ax, [0, nMax]); %[output:1d3ce009]
%[text] Wait for MATLAB to catch up.
pause(2);
%[text] Save the picture.
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.pdf"); %[output:1d3ce009]
exportgraphics(fig, PictureFolder + filesep + "Time in system histogram.svg"); %[output:1d3ce009]

% histogram for W_q
fig = figure(); %[output:134c7393]
t = tiledlayout(fig,1,1); %[output:134c7393]
ax = nexttile(t); %[output:134c7393]
TimeWaiting = WaitingInSystemSamples;
